                 _ => absDiff.TotalMinutes switch
                 {
                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
                     _ => $"{(int)absDiff.TotalSeconds} seconds"
                 }
             }
         };

         return isFuture ? $"in {result}" : $"{result} ago";
     }
 }

