 /// Spanish ordinalizer providing locale-specific ordinal formatting.
 /// </summary>
 public sealed class SpanishOrdinalizer : DefaultOrdinalizer
 {
     /// <inheritdoc />
     public override string Convert(int number, string numberString) =>
         numberString + ".º";
 }

